sql:
SELECT AVG(salary) AS average_salary
FROM compensation
WHERE year = 2022;

SELECT company_id, COUNT(*) as number_of_executives
FROM companies_executives
GROUP BY company_id;

SELECT year
FROM year
WHERE is_current_year = 1;

SELECT COUNT(executive_id) 
FROM companies_executives 
WHERE company_id = 0;

SELECT MAX(julianday('now') - julianday(start_date)) AS max_years_held
FROM executives_positions
WHERE end_date IS NULL;

SELECT executive_id, COUNT(position_id) AS position_count
FROM executives_positions
GROUP BY executive_id;

SELECT AVG(total) AS average_total_compensation
FROM compensation
WHERE year = 2021;

external_knowledge:
- "at the helm" refers to executives in their positions; 
- "steering the ship" refers to the executives' positions or roles in the company; 
- "break the bank" is an idiom for exceeding a certain amount, in this case, total compensation over $500,000; 
- "high-flyers" refers to high-compensated executives.
